@Test
void testSessionWindowsWithLateDataAndSideOutput() throws Exception {
    // Test for late data side output handling in merging windows (session windows)
    // This test verifies that late-arriving elements are properly sent to the side output
    // when using session windows with allowedLateness and sideOutputLateData configuration

    final int sessionSize = 3; // 3 seconds gap between events to create new session
    final long allowedLateness = 0;

    ListStateDescriptor<Tuple2<String, Integer>> stateDesc =
            new ListStateDescriptor<>(
                    "window-contents",
                    STRING_INT_TUPLE.createSerializer(new SerializerConfigImpl()));

    WindowOperatorFactory<
                    String,
                    Tuple2<String, Integer>,
                    Iterable<Tuple2<String, Integer>>,
                    Tuple2<String, Integer>,
                    TimeWindow>
            operator =
                    new WindowOperatorFactory<>(
                            EventTimeSessionWindows.withGap(Duration.ofSeconds(sessionSize)),
                            new TimeWindow.Serializer(),
                            new TupleKeySelector(),
                            BasicTypeInfo.STRING_TYPE_INFO.createSerializer(
                                    new SerializerConfigImpl()),
                            stateDesc,
                            new InternalIterableWindowFunction<>(new PassThroughWindowFunction<>()),
                            EventTimeTrigger.create(),
                            allowedLateness,
                            lateOutputTag);

    OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple2<String, Integer>>
            testHarness = createTestHarness(operator);

    testHarness.open();

    ConcurrentLinkedQueue<Object> expectedOutput = new ConcurrentLinkedQueue<>();
    ConcurrentLinkedQueue<Object> expectedLateOutput = new ConcurrentLinkedQueue<>();

    // Create a session window by sending two elements with gap < sessionSize
    // Elements at time 100 and 200 should create window [100, 203]
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 100));
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 2), 200));

    // Advance watermark to 500
    // Window [100, 203] has maxTimestamp + allowedLateness = 203 + 0 = 203
    // So window should expire when watermark >= 203
    testHarness.processWatermark(new Watermark(500));

    // Window should have fired and generated output
    expectedOutput.add(new StreamRecord<>(new Tuple2<>("key1", 1), 202));
    expectedOutput.add(new StreamRecord<>(new Tuple2<>("key1", 2), 202));
    expectedOutput.add(new Watermark(500));

    TestHarnessUtil.assertOutputEqualsSorted(
            "Output was not correct.",
            expectedOutput,
            testHarness.getOutput(),
            new Tuple2ResultSortComparator());

    // Clear the output queue
    testHarness.getOutput().clear();

    // Send a late element at time 150
    // This is after the window has been closed (watermark is at 500)
    // This element should be sent to the side output, not dropped
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 3), 150));

    // Expected: element goes to side output, not to main output
    expectedLateOutput.add(new StreamRecord<>(new Tuple2<>("key1", 3), 150));

    // Get the late output
    ConcurrentLinkedQueue<Object> lateOutput = (ConcurrentLinkedQueue<Object>) testHarness.getSideOutput(lateOutputTag);

    TestHarnessUtil.assertOutputEqualsSorted(
            "Late output was not correct.",
            expectedLateOutput,
            lateOutput,
            new Tuple2ResultSortComparator());

    testHarness.close();
}

